/**
 * @param {string} url - url to read html content
 * @param {string} serverUrl - replace domain name
 * @returns {Promise.<string>}
 */
export async function JS_ReadHTML(url, serverUrl) {
	// BEGIN USER CODE
    function replacePath(html)
    {
        var pattern1 = /<script\s+src='\/([^']+)'/g;
        var pattern2 = /\$\.getScript\('\/([^']+)'/g;
        //var pattern1 = /<script\s+src='(\.\.)+/g;
        //var pattern2 = /\$\.getScript\('(\.\.)+/g;
		//console.warn(serverUrl);
        var modifiedHtml = html.replace(pattern1, "<script src='" + serverUrl + "/$1'");
        modifiedHtml = modifiedHtml.replace(pattern2, "$.getScript('" + serverUrl + "/$1'");
        //var modifiedHtml = html.replace(pattern1, "<script src='" + serverUrl);
        //modifiedHtml = modifiedHtml.replace(pattern2, "$.getScript('" + serverUrl);
        //console.log(modifiedHtml);

        return modifiedHtml;
    }

    function annotateSPCFunc(modifiedHtml) {
        var script = "<script type='text/javascript'>"+
        "function annotateSPC(var1, var2, var3) " +
        "{ window.parent.annotateSPC(var1,var2,var3);}"+
        "</script>"
        modifiedHtml = modifiedHtml.concat(script);
        return modifiedHtml;
    }
 
 
fetch(url)
    .then(response => response.text())
    .then(html => {
        var modifiedHtml = replacePath(html);
        modifiedHtml = annotateSPCFunc(modifiedHtml);
        var iframe = document.getElementById('spcIframe');
        iframe.srcdoc = modifiedHtml;
        iframe.frameBorder = '0';
    })
    .catch(error => {
        console.error('Error fetching HTML:', error);
    });	

	// END USER CODE
}
